import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"派息","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/dividend.md","filePath":"zh-CN/stock-trading/corporate-actions/dividend.md"}'),o={name:"stock-trading/corporate-actions/dividend.md"};function n(d,a,l,c,s,p){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="派息" tabindex="-1">派息 <a class="header-anchor" href="#派息" aria-label="Permalink to &quot;派息&quot;">​</a></h1><p>派息参与条件、三个关键日期、派息收费及查看派息信息。</p><h2 id="什么是派息" tabindex="-1">什么是派息 <a class="header-anchor" href="#什么是派息" aria-label="Permalink to &quot;什么是派息&quot;">​</a></h2><p>派息是指上市公司向股东派送现金。在除权日前一天收盘后，如果客户持有上市公司的股票，则会参与派息。</p><p>若您符合派息要求，长桥会在派息日后 1-3 个交易日完成处理，将现金股息发放到账。</p><p>除权日当天，上市公司的股票价格会下跌，所以股东会在开盘前看到自己的盈亏是亏损状态。这部分亏损的金额会变换成现金股息派送到股东的账户中（持仓成本并不进行变动）。</p><p>派息后，股东的持仓由全部正股，变成了全部正股（价格下跌）+ 现金股息（金额为正股下跌的部分）。</p><h2 id="什么是特殊派息" tabindex="-1">什么是特殊派息 <a class="header-anchor" href="#什么是特殊派息" aria-label="Permalink to &quot;什么是特殊派息&quot;">​</a></h2><p>特殊派息是派息的一种，派息的理由具有特殊性，例如上市公司的某些投资赚钱，而不是主营业务赚钱，所以派发特殊股息。其参与条件、处理时间以及除权日股价和股东盈亏变化与普通派息一致。</p><h2 id="三个关键日期" tabindex="-1">三个关键日期 <a class="header-anchor" href="#三个关键日期" aria-label="Permalink to &quot;三个关键日期&quot;">​</a></h2><p>除净日（Ex-Dividend Date）：这一日的前一交易日持有该股票的客户可享有派息的权利，而除净日当天或之后买入的客户则没有资格享有派息。&quot;除息日&quot;、&quot;除权日&quot;等与&quot;除净日&quot;是相同的概念，差别仅仅是权益派发的形式不同。</p><p>登记日（Dividend Date）：有资格享有派息的最后日期。对大部分股票而言，通常是除净日的前一天，客户只要在股权登记日买入或持有该公司的股票，即可确认收取这一次派息。</p><p>派息日（Declaration Date）：又可称为股息发放日、红利发放日。凡在股权登记日在股东花名册上的合格客户，便能在派息日这一天收取到对应股数的股息。</p><h2 id="派息收费" tabindex="-1">派息收费 <a class="header-anchor" href="#派息收费" aria-label="Permalink to &quot;派息收费&quot;">​</a></h2><p>港股发生现金派息，长桥会代交易所收取两类费用：</p><p>登记及过户费：1.5 港元/手，不足 1 手按 1 手收费（以上次登记日到此次登记日之间客户新增股票数量计算，若无新增则不收取）。</p><p>分红服务费：按现金股息总额 0.2%，最低 30 港元。</p><h2 id="如何查看派息信息" tabindex="-1">如何查看派息信息 <a class="header-anchor" href="#如何查看派息信息" aria-label="Permalink to &quot;如何查看派息信息&quot;">​</a></h2><p>可在个股页面 - 全景 - 百科 - 分红信息处查看分红（派息）相关记录。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/corporate-actions/general-meeting">股东大会</a></li><li><a href="/wiki/stock-trading/corporate-actions">公司行动</a></li><li><a href="/wiki/stock-trading">股票交易</a></li></ul>',21)])])}const _=e(o,[["render",n]]);export{u as __pageData,_ as default};
